alpha and beta from reparameterization
 real K = exp(eta);
 real alpha = phi * K;
 real beta = (1 - phi) * K;

 // Prior in (phi, eta) space:
 // p(alpha,beta) = (alpha+beta)^{-5/2}
 // Jacobian from (alpha,beta) to (phi,K) is K
 // Jacobian from K to eta is exp(eta) = K
 // So p(phi, eta) = K^{-5/2} * K * K^{-1} ... 
 // Actually: p(phi,K)

 = K^{-5/2} * K = K^{-3/2}
  // p(phi,eta) = K^{-3/2} * K = K^{-1/2} = exp(-eta/2)
  target += -0.5 * eta;

  // Hierarchical prior: theta_i ~ Beta(alpha, beta)
  theta ~ beta(alpha, beta);

  // Likelihood: y_i ~ Binomial(n_i, theta_i)
  y ~ binomial(theta, n);
}

